#!/usr/bin/env node
// Print the newest release's notes for pasting into the GitHub release body:
// the human summary plus the autogenerated changelog, minus the frontmatter and
// the Downloads block. Robust to the Downloads block changing length (the old
// shell version hardcoded its line count).
import { readFileSync } from 'node:fs'
import path from 'node:path'

import {
  BLOG_DIR,
  findLatestReleasePost,
  parseReleasePost,
  splitReleaseBody,
} from './releaseBlog.mjs'

const newest = findLatestReleasePost()
const { body } = parseReleasePost(
  readFileSync(path.join(BLOG_DIR, newest), 'utf8'),
  newest,
)
const { notes, changelog } = splitReleaseBody(body)

process.stdout.write(`${[notes, changelog].filter(Boolean).join('\n\n')}\n`)
